static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 2048;
static constexpr uint32_t HARD_CAP_ELEMS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Ca6k00329CustomTilingData tiling;
    const gert::StorageShape *x_shape = context->GetInputShape(0);
    const auto &origin_shape = x_shape->GetOriginShape();
    uint32_t dimNum = origin_shape.GetDimNum();
    uint32_t batch = 1, channels = 1, height = 1, width = 1;
    if (dimNum == 4) {
        batch = origin_shape.GetDim(0);
        channels = origin_shape.GetDim(1);
        height = origin_shape.GetDim(2);
        width = origin_shape.GetDim(3);
    } else if (dimNum == 3) {
        batch = origin_shape.GetDim(0);
        channels = origin_shape.GetDim(1);
        height = origin_shape.GetDim(2);
        width = 1;
    } else if (dimNum == 2) {
        batch = origin_shape.GetDim(0);
        channels = origin_shape.GetDim(1);
        height = 1;
        width = 1;
    }
    uint32_t totalLength = origin_shape.GetShapeSize();

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *eps_ptr = attrs->GetAttrPointer<float>(0);
    float eps = (eps_ptr != nullptr) ? *eps_ptr : 1e-5f;

    uint32_t maxTile = UB_BUDGET_BYTES / 12; // 3 floats per element (x, y, temp)
    maxTile = AlignDown(maxTile, ALIGN_ELEMS);
    if (maxTile < ALIGN_ELEMS) maxTile = ALIGN_ELEMS;
    if (maxTile > HARD_CAP_ELEMS) maxTile = AlignDown(HARD_CAP_ELEMS, ALIGN_ELEMS);

    uint32_t spatialSize = batch * height * width;
    uint32_t tileLen = maxTile;
    if (spatialSize < tileLen) {
        const uint32_t aligned = AlignDown(spatialSize, ALIGN_ELEMS);
        tileLen = (aligned > 0) ? aligned : spatialSize;
    }
    if (tileLen == 0) tileLen = 1;

    uint32_t blockDim = 1; // single block because kernel processes all channels sequentially
    context->SetBlockDim(blockDim);

    tiling.set_totalLength(totalLength);
    tiling.set_tileLength(tileLen);
    tiling.set_blockDim(blockDim);
    tiling.set_batch(batch);
    tiling.set_channels(channels);
    tiling.set_height(height);
    tiling.set_width(width);
    tiling.set_eps(eps);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

